"use client";

import { ark } from "@ark-ui/react";
import { Portal } from "@ark-ui/react";
import {
  ColorPicker as ArkColorPicker,
  parseColor as parseColorArk,
  type ColorPickerValueChangeDetails,
} from "@ark-ui/react/color-picker";
import { Pipette } from "lucide-react";
import {React.useState } from "react";
import type React from "react";
import { cn } from "@/lib/utils";
import type { InputProps } from "./input";
import { Button } from "./button";

export const parseColor = parseColorArk;

export const ColorPicker = (
  props: React.ComponentProps<typeof ArkColorPicker.Root>
) => {
  const {
    lazyMount = true,
    unmountOnExit = true,
    className,
    children,
    ...rest
  } = props;

  return (
    <ArkColorPicker.Root
      className={cn(
        "w-full",
        "flex flex-col gap-2",
        "text-foreground",
        className
      )}
      data-slot="color-picker"
      lazyMount={lazyMount}
      unmountOnExit={unmountOnExit}
      {...rest}
    >
      {children}

      <ArkColorPicker.HiddenInput />
    </ArkColorPicker.Root>
  );
};

export const ColorPickerControl = (
  props: React.ComponentProps<typeof ArkColorPicker.Control>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.Control
      className={cn("flex flex-row items-center gap-2", className)}
      data-slot="color-picker-control"
      {...rest}
    />
  );
};

export const ColorPickerTrigger = (
  props: React.ComponentProps<typeof ArkColorPicker.Trigger>
) => {
  return <ArkColorPicker.Trigger data-slot="color-picker-trigger" {...props} />;
};

export const ColorPickerTransparencyGrid = (
  props: React.ComponentProps<typeof ArkColorPicker.TransparencyGrid>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.TransparencyGrid
      className={cn(
        "size-full rounded-[calc(var(--radius-sm)-0.5px)]",
        "bg-[linear-gradient(45deg,#e4e4e4_25%,transparent_25%),linear-gradient(-45deg,#e4e4e4_25%,transparent_25%),linear-gradient(45deg,transparent_75%,#e4e4e4_75%),linear-gradient(-45deg,transparent_75%,#e4e4e4_75%)]",
        "bg-position-[0_0,0_4px,4px_-4px,-4px_0] bg-size-(--spacing(2))",
        className
      )}
      {...rest}
    />
  );
};

export const ColorPickerContent = (
  props: React.ComponentProps<typeof ArkColorPicker.Content>
) => {
  const { className, ...rest } = props;

  return (
    <Portal>
      <ArkColorPicker.Positioner data-slot="color-picker-positioner">
        <ArkColorPicker.Content
          className={cn(
            "z-50",
            "relative",
            "max-h-96 min-w-64",
            "flex flex-col gap-3",
            "p-4",
            "origin-(--transform-origin)",
            "bg-popover",
            "rounded-xl border shadow-lg/5",
            "outline-none",
            "data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95 data-[state=open]:animate-in",
            "data-[state=closed]:fade-out-0 data-[state=closed]:zoom-out-95 data-[state=closed]:animate-out",
            className
          )}
          data-slot="color-picker-content"
          {...rest}
        />
      </ArkColorPicker.Positioner>
    </Portal>
  );
};

export const ColorPickerSlider = (
  props: React.ComponentProps<typeof ArkColorPicker.ChannelSlider>
) => {
  const { className, children, ...rest } = props;

  return (
    <ArkColorPicker.ChannelSlider
      className={cn("relative h-2.5 flex-1", "rounded-full border", className)}
      data-slot="color-picker-channel-slider"
      {...rest}
    >
      {children}

      <ArkColorPicker.ChannelSliderTrack
        className="h-2.5 w-full rounded-sm"
        data-slot="color-picker-channel-slider-track"
      />
      <ArkColorPicker.ChannelSliderThumb
        className={cn(
          "size-3.5",
          "-translate-1/2",
          "rounded-full",
          "border-2 border-white shadow-xs/5",
          "outline-none ring-1 ring-border/64"
        )}
        data-slot="color-picker-channel-slider-thumb"
      />
    </ArkColorPicker.ChannelSlider>
  );
};

export const ColorPickerEyeDropperTrigger = (
  props: React.ComponentProps<typeof ArkColorPicker.EyeDropperTrigger>
) => {
  const { className, children, ...rest } = props;

  return (
    <ArkColorPicker.EyeDropperTrigger
      data-slot="color-picker-eye-dropper"
      {...rest}
      asChild
    >
      <Button className={cn(className)} size="icon-md" variant="outline">
        {children || <Pipette />}
      </Button>
    </ArkColorPicker.EyeDropperTrigger>
  );
};

export const ColorPickerSwatchGroup = (
  props: React.ComponentProps<typeof ArkColorPicker.SwatchGroup>
) => {
  const { className, ...rest } = props;
  return (
    <ArkColorPicker.SwatchGroup
      className={cn("flex flex-wrap gap-2", className)}
      data-slot="color-picker-swatch-group"
      {...rest}
    />
  );
};

export const ColorPickerSwatchTrigger = (
  props: React.ComponentProps<typeof ArkColorPicker.SwatchTrigger>
) => {
  const { className, ...rest } = props;
  return (
    <ArkColorPicker.SwatchTrigger
      className={cn(
        "flex items-center justify-center rounded-md p-0 outline-none ring-border/64 focus-visible:ring-2",
        className
      )}
      data-slot="color-picker-swatch-trigger"
      {...rest}
    />
  );
};

export const ColorPickerSwatch = (
  props: React.ComponentProps<typeof ArkColorPicker.Swatch>
) => {
  const { className, ...rest } = props;
  return (
    <ArkColorPicker.Swatch
      className={cn(
        "relative grid size-8 shrink-0 place-items-center overflow-hidden rounded-md border shadow-sm",
        className
      )}
      data-slot="color-picker-swatch"
      {...rest}
    />
  );
};

export const ColorPickerSwatchIndicator = (
  props: React.ComponentProps<typeof ArkColorPicker.SwatchIndicator>
) => {
  const { className, ...rest } = props;
  return (
    <ArkColorPicker.SwatchIndicator
      className={cn(
        "absolute inset-0 flex items-center justify-center text-sm text-white drop-shadow-sm [&_svg]:size-4",
        className
      )}
      data-slot="color-picker-swatch-indicator"
      {...rest}
    />
  );
};

export const ColorPickerValue = (
  props: React.ComponentProps<typeof ArkColorPicker.ValueText>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ValueText
      className={cn("font-medium text-sm", className)}
      data-slot="color-picker-value"
      {...rest}
    />
  );
};

export const ColorPickerValueSwatch = (
  props: React.ComponentProps<typeof ArkColorPicker.ValueSwatch>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ValueSwatch
      className={cn(
        "relative size-8 shrink-0 overflow-hidden rounded-full border",
        className
      )}
      data-slot="color-picker-value-swatch"
      {...rest}
    />
  );
};

// ============ Color Area (merged from color-area) ============

interface ColorPickerAreaProps
  extends React.ComponentProps<typeof ArkColorPicker.Area> {
  showDots?: boolean;
}

export const ColorPickerArea = (props: ColorPickerAreaProps) => {
  const { className, showDots = false, ...rest } = props;

  return (
    <ArkColorPicker.Area
      className={cn(
        "relative size-full touch-none rounded-[inherit]",
        {
          "after:pointer-events-none after:absolute after:inset-0 after:rounded-[inherit] after:bg-[radial-gradient(circle,#fff3_1px,#0000_1px)] after:bg-size-[8px_8px]":
            showDots,
        },
        className
      )}
      data-slot="color-picker-area"
      {...rest}
    />
  );
};

export const ColorPickerAreaBackground = (
  props: React.ComponentProps<typeof ArkColorPicker.AreaBackground>
) => (
  <ArkColorPicker.AreaBackground
    className={cn("size-full rounded-[inherit]")}
    data-slot="color-picker-area-background"
    {...props}
  />
);

export const ColorPickerAreaThumb = (
  props: React.ComponentProps<typeof ArkColorPicker.AreaThumb>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.AreaThumb
      className={cn(
        "size-4.5",
        "rounded-full border-[3px] border-white shadow-[0_0_0_1px_rgba(0,0,0,0.1),inset_0_0_0_1px_rgba(0,0,0,0.1)]",
        "outline-none ring-border/64",
        "data-disabled:pointer-events-none data-disabled:opacity-64",
        className
      )}
      data-slot="color-picker-area-thumb"
      style={{ background: "var(--color)" }}
      {...rest}
    />
  );
};

interface ColorPickerAreaRootProps
  extends Omit<
      React.ComponentProps<typeof ArkColorPicker.Root>,
      "defaultValue" | "value"
    >,
    Pick<
      React.ComponentProps<typeof ArkColorPicker.Area>,
      "xChannel" | "yChannel"
    > {
  defaultValue?: string;
  showDots?: boolean;
  value?: string;
}

export const ColorPickerAreaRoot = (props: ColorPickerAreaRootProps) => {
  const {
    showDots = false,
    value,
    defaultValue,
    xChannel,
    yChannel,
    onValueChange,
    className,
    children,
    ...rest
  } = props;

  const [internalValue, setInternalValue] = React.useState(defaultValue);

  const isControlled = value !== undefined;

  const handleChangeValue = (e: ColorPickerValueChangeDetails) => {
    if (isControlled) {
      onValueChange?.(e);
    } else {
      setInternalValue(e.valueAsString);
    }
  };

  return (
    <ArkColorPicker.Root
      className={cn(
        "size-full h-56 max-w-56",
        "rounded-2xl border shadow-md/5",
        "data-disabled:pointer-events-none data-disabled:opacity-64",
        className
      )}
      data-slot="color-picker-area-root"
      defaultValue={internalValue ? parseColor(internalValue) : undefined}
      inline
      onValueChange={handleChangeValue}
      value={isControlled ? parseColor(value) : undefined}
      {...rest}
    >
      <ColorPickerArea showDots={showDots} xChannel={xChannel} yChannel={yChannel}>
        <ColorPickerAreaBackground />
        {children ?? <ColorPickerAreaThumb />}
      </ColorPickerArea>
      <ArkColorPicker.HiddenInput />
    </ArkColorPicker.Root>
  );
};

// ============ Color Input (merged from color-input) ============

interface ColorPickerInputProps
  extends Omit<
      React.ComponentProps<typeof ArkColorPicker.Root>,
      "value" | "defaultValue"
    >,
    Partial<
      Pick<React.ComponentProps<typeof ArkColorPicker.ChannelInput>, "channel">
    > {
  defaultValue?: string;
  value?: string;
}

export const ColorPickerInput = (props: ColorPickerInputProps) => {
  const {
    value,
    defaultValue,
    channel = "hex",
    onValueChange,
    className,
    children,
    ...rest
  } = props;

  const [internalValue, setInternalValue] = React.useState(defaultValue);
  const isControlled = value !== undefined;

  const handleChangeValue = (e: ColorPickerValueChangeDetails) => {
    if (isControlled) {
      onValueChange?.(e);
    } else {
      setInternalValue(e.valueAsString);
    }
  };

  return (
    <ArkColorPicker.Root
      className={cn("group/color-input", className)}
      data-slot="color-picker-input"
      defaultValue={internalValue ? parseColor(internalValue) : undefined}
      inline
      onValueChange={handleChangeValue}
      value={isControlled ? parseColor(value) : undefined}
      {...rest}
    >
      {children}
      <ArkColorPicker.HiddenInput />
    </ArkColorPicker.Root>
  );
};

interface ColorPickerInputProps
  extends Partial<
      Omit<React.ComponentProps<typeof ArkColorPicker.ChannelInput>, "size">
    >,
    Pick<InputProps, "size"> {}

export const ColorPickerInput = (props: ColorPickerInputProps) => {
  const { size = "md", channel = "hex", ...rest } = props;

  return (
    <ArkColorPicker.ChannelInput
      asChild
      channel={channel}
      data-slot="color-picker-input-field"
      {...rest}
    />
  );
};

export const ColorPickerSwatchPreview = (
  props: React.ComponentProps<typeof ark.div>
) => {
  const { className, ...rest } = props;

  return (
    <ark.div
      className={cn(
        "relative",
        "size-8",
        "shrink-0",
        "rounded-full border",
        "pointer-events-none overflow-hidden",
        "group-data-[size=lg]/input-group:size-5",
        "group-data-[size=md]/input-group:size-4",
        "group-data-[size=sm]/input-group:size-3.5",
        "group-data-disabled/color-input:opacity-64",
        className
      )}
      data-slot="color-picker-input-swatch"
      {...rest}
    >
      <ArkColorPicker.TransparencyGrid
        className={cn(
          "size-full rounded-[calc(var(--radius-sm)-0.5px)]",
          "bg-[linear-gradient(45deg,#e4e4e4_25%,transparent_25%),linear-gradient(-45deg,#e4e4e4_25%,transparent_25%),linear-gradient(45deg,transparent_75%,#e4e4e4_75%),linear-gradient(-45deg,transparent_75%,#e4e4e4_75%)]",
          "bg-position-[0_0,0_4px,4px_-4px,-4px_0] bg-size-(--spacing(2))"
        )}
      />
      <ArkColorPicker.ValueSwatch className="z-1 size-full" />
    </ark.div>
  );
};

// ============ Color Slider (merged from color-slider) ============

export const ColorPicker = (
  props: React.ComponentProps<typeof ArkColorPicker.Root>
) => {
  const { className, children, ...rest } = props;

  return (
    <ArkColorPicker.Root
      className={cn("flex w-full flex-col gap-2 text-foreground", className)}
      data-slot="color-picker-slider-root"
      inline
      {...rest}
    >
      {children}
      <ArkColorPicker.HiddenInput />
    </ArkColorPicker.Root>
  );
};

export const ColorPickerSlider = (
  props: React.ComponentProps<typeof ArkColorPicker.ChannelSlider>
) => {
  const { className, children, ...rest } = props;

  return (
    <ArkColorPicker.ChannelSlider
      className={cn(
        "relative h-2.5 flex-1 rounded-full border",
        "data-[orientation=vertical]:h-40 data-[orientation=vertical]:w-2.5",
        className
      )}
      data-slot="color-picker-slider"
      {...rest}
    >
      {children}
      <ArkColorPicker.ChannelSliderTrack
        className="h-2.5 w-full rounded-sm data-[orientation=vertical]:h-full data-[orientation=vertical]:w-2.5"
        data-slot="color-picker-slider-track"
      />
      <ArkColorPicker.ChannelSliderThumb
        className={cn(
          "-translate-1/2 size-3.5",
          "rounded-full border-2 border-white shadow-xs/5",
          "outline-none ring-1 ring-border/64"
        )}
        data-slot="color-picker-slider-thumb"
      />
    </ArkColorPicker.ChannelSlider>
  );
};

export const ColorPickerTransparencyGrid = ColorPickerTransparencyGrid;

export const ColorPickerValue = ColorPickerValue;

export const ColorPickerValueSwatch = (
  props: React.ComponentProps<typeof ArkColorPicker.ValueSwatch>
) => {
  const { className, ...rest } = props;

  return (
    <ArkColorPicker.ValueSwatch
      className={cn("z-1 size-full", className)}
      data-slot="color-picker-slider-value-swatch"
      {...rest}
    />
  );
};

// ============ Color Swatch Display (merged from color-swatch) ============

export interface ColorPickerSwatchDisplayProps
  extends React.ComponentProps<typeof ArkColorPicker.Swatch> {}

export const ColorPickerSwatchDisplay = (
  props: ColorPickerSwatchDisplayProps
) => {
  const { className, value, ...rest } = props;

  const colorValue =
    typeof value === "string" ? parseColor(value) : value;

  return (
    <ArkColorPicker.Root inline defaultValue={colorValue}>
      <ArkColorPicker.Swatch
        className={cn(
          "relative",
          "size-8",
          "shrink-0",
          "rounded-full",
          "overflow-hidden",
          "after:absolute after:inset-0 after:rounded-[inherit] after:border after:border-border after:mix-blend-darken dark:after:mix-blend-lighten",
          className
        )}
        data-slot="color-picker-swatch-display"
        respectAlpha
        {...rest}
      />
    </ArkColorPicker.Root>
  );
};

// Aliases for swatch picker pattern (ColorPicker with inline)
export const ColorPicker = ColorPicker;
export const ColorPickerSwatchGroup = ColorPickerSwatchGroup;
export const ColorPickerSwatchTrigger = ColorPickerSwatchTrigger;
export const ColorPickerSwatch = ColorPickerSwatch;
export const ColorPickerSwatchIndicator = ColorPickerSwatchIndicator;
export const ColorPickerValue = ColorPickerValue;
